revision.text:
{{Documentation subpage}}
{{High-use}}
<!-- PLEASE ADD CATEGORIES AT THE BOTTOM OF THIS PAGE -->
{{CS1 wrapper|base=cite web|spell=z}}
{{Underused external link template|http://plants.usda.gov/|https://plants.sc.egov.usda.gov/}}

== Purpose ==

Provides an easy way to cite [[Natural Resources Conservation Service]] PLANTS database.

== Usage ==

{{tlc|{{replace|{{PAGENAME}}|/doc||1}}|symbol{{=}}|taxon{{=}}|access-date{{=}}{{#time: j F Y}}}}

 <nowiki>{{</nowiki>{{replace|{{PAGENAME}}|/doc||1}}
 <nowiki> | symbol = 
 | taxon = 
 | access-date = 
 }}</nowiki>

Other parameters of {{tlx|cite web}} are available, such as {{para|mode}} and {{para|harv}}.

== Example ==

# {{tlc|{{replace|{{PAGENAME}}|/doc||1}}|symbol{{=}}RUID|taxon{{=}}Rubus idaeus|access-date{{=}}{{date}}}}
# {{tlc|{{replace|{{PAGENAME}}|/doc||1}}|symbol{{=}}RUID|taxon{{=}}Rubus idaeus|access-date{{=}}{{date}}|mode{{=}}cs2}}
:: &darr;
# {{ {{replace|{{PAGENAME}}|/doc||1}}|symbol=RUID|taxon=Rubus idaeus|access-date={{date}}}}
# {{ {{replace|{{PAGENAME}}|/doc||1}}|symbol=RUID|taxon=Rubus idaeus|access-date={{date}}|mode=cs2}}

== See also ==
* [[:Category:Articles using Template:PLANTS with missing parameters]]: tracks cases that have neither {{para|name}} nor {{para|taxon}}

<includeonly>{{Sandbox other||
<!-- CATEGORIES HERE -->
[[Category:Biology source templates]]
[[Category:Botany external link templates]]
}}</includeonly>
<templatedata>
{
	"params": {
		"date": {
			"label": "Date",
			"description": "Date of the data",
			"example": "1 November 2023",
			"type": "date",
			"suggested": true
		},
		"symbol": {
			"label": "Symbol",
			"description": "Symbol at the end of the link",
			"example": "RUID",
			"type": "string",
			"required": true,
			"aliases": [
				"id"
			]
		},
		"taxon": {
			"label": "Taxonomic name",
			"description": "Taxonomic name of the link's subject",
			"example": "Rubus idaeus",
			"type": "string",
			"required": true,
			"aliases": [
				"name"
			]
		},
		"access-date": {
			"label": "Access date",
			"description": "Date the link was accessed",
			"example": "31 November 2022",
			"type": "date",
			"suggested": true
		}
	},
	"description": "Provides an easy way to cite Natural Resources Conservation Service PLANTS database.",
	"paramOrder": [
		"date",
		"symbol",
		"taxon",
		"access-date"
	],
	"format": "inline"
}
</templatedata>

